/**
 * @swagger
 * tags:
 *   - name: Admin - Franchise Payouts
 *     description: Administrative tools for monitoring and marking Franchise Repurchase Payouts as paid.
 *   - name: Franchise - Finances
 *     description: Financial tracking and live Repurchase BV accumulation metrics for the logged-in Franchise.
 */

/**
 * @swagger
 * /api/v1/admin/franchise-payout/list:
 *   get:
 *     summary: Get paginated list of generated Franchise Repurchase Payouts
 *     description: View all monthly payouts generated by the system for franchises.
 *     tags: [Admin - Franchise Payouts]
 *     security:
 *       - bearerAuth: []
 *     parameters:
 *       - in: query
 *         name: page
 *         schema: { type: integer, default: 1 }
 *       - in: query
 *         name: limit
 *         schema: { type: integer, default: 10 }
 *       - in: query
 *         name: status
 *         schema: { type: string, enum: [pending, paid] }
 *     responses:
 *       200:
 *         description: Payout list fetched successfully
 */

/**
 * @swagger
 * /api/v1/admin/franchise-payout/live-bv:
 *   get:
 *     summary: View real-time, ongoing BV accumulations for franchises this month
 *     description: Watch BV accumulate live throughout the month before the payout triggers.
 *     tags: [Admin - Franchise Payouts]
 *     security:
 *       - bearerAuth: []
 *     parameters:
 *       - in: query
 *         name: hasBvOnly
 *         schema: { type: boolean, default: true }
 *     responses:
 *       200:
 *         description: Live BV states fetched successfully
 */

/**
 * @swagger
 * /api/v1/admin/franchise-payout/{id}/mark-paid:
 *   patch:
 *     summary: Manually mark a pending Franchise Payout as Paid
 *     description: Updates the status of a specific generated payout to paid.
 *     tags: [Admin - Franchise Payouts]
 *     security:
 *       - bearerAuth: []
 *     parameters:
 *       - in: path
 *         name: id
 *         required: true
 *         schema: { type: string }
 *     requestBody:
 *       required: false
 *       content:
 *         application/json:
 *           schema:
 *             type: object
 *             properties:
 *               transactionRef: { type: string, example: "NEFT-12345678" }
 *     responses:
 *       200:
 *         description: Payout marked as paid
 */

/**
 * @swagger
 * /api/v1/franchise/payout/history:
 *   get:
 *     summary: Get personal Franchise Repurchase Payout history
 *     description: Returns a list of all successful monthly payouts generated for the logged-in franchise.
 *     tags: [Franchise - Finances]
 *     security:
 *       - bearerAuth: []
 *     responses:
 *       200:
 *         description: History fetched successfully
 */

/**
 * @swagger
 * /api/v1/franchise/payout/live-bv:
 *   get:
 *     summary: Get live real-time metrics of BV processed this month
 *     description: See the live amount of BV accumulated this month and the estimated 10% payout projection.
 *     tags: [Franchise - Finances]
 *     security:
 *       - bearerAuth: []
 *     responses:
 *       200:
 *         description: Live BV fetched successfully
 */
